cpp_content = '\n// ═══════════════════════════════════════════════════════════════\n// 4. PuzzleWindowBase 体系实现\n// ═══════════════════════════════════════════════════════════════\nPuzzleWindowBase::PuzzleWindowBase(const std::string& t, sf::Vector2f p, float w, float h, const sf::Font& font)\n    : UIComponent(p, w, h), title(t), uiFont(&font) {\n    frame.setFillColor(C::WindowBody);\n    titleBar.setFillColor(C::TitleActive);\n    titleText.setFont(font);\n    titleText.setCharacterSize(12);\n    titleText.setString(U8(title));\n    titleText.setFillColor(C::TextWhite);\n    titleText.setStyle(sf::Text::Bold);\n}\n\nsf::FloatRect PuzzleWindowBase::titleBarRect() const { return {position, {width, TITLEBAR_H}}; }\nsf::FloatRect PuzzleWindowBase::closeBtnRect() const { return {position.x + width - BORDER - CAPTION_BTN - 2.f, position.y + BORDER + 2.f, CAPTION_BTN, CAPTION_BTN}; }\nsf::FloatRect PuzzleWindowBase::maxBtnRect() const { return {position.x + width - BORDER - CAPTION_BTN*2 - 4.f, position.y + BORDER + 2.f, CAPTION_BTN, CAPTION_BTN}; }\nsf::FloatRect PuzzleWindowBase::minBtnRect() const { return {position.x + width - BORDER - CAPTION_BTN*3 - 4.f, position.y + BORDER + 2.f, CAPTION_BTN, CAPTION_BTN}; }\nsf::FloatRect PuzzleWindowBase::clientRect() const { return {position.x + BORDER, position.y + TITLEBAR_H + 1.f, width - 2*BORDER, height - TITLEBAR_H - BORDER - 1.f}; }\n\nvoid PuzzleWindowBase::dragUpdate(sf::Vector2f mousePos) {\n    position = mousePos - dragOffset;\n    if (position.y < 0) position.y = 0;\n    if (position.y > DESKTOP_H - TITLEBAR_H) position.y = DESKTOP_H - TITLEBAR_H;\n}\n\nvoid PuzzleWindowBase::closeWindow() { isOpen = false; }\nvoid PuzzleWindowBase::minimizeWindow() { isMinimized = true; }\nvoid PuzzleWindowBase::restoreFromTaskbar() {\n    isMinimized = false;\n    if (g_Desktop) g_Desktop->setActiveWindow(this);\n}\nvoid PuzzleWindowBase::toggleMaximize() {\n    if (!canMaximize) return;\n    if (isMaximized) {\n        position = restorePos;\n        width = restoreW;\n        height = restoreH;\n        isMaximized = false;\n    } else {\n        restorePos = position;\n        restoreW = width;\n        restoreH = height;\n        position = {0, 0};\n        width = WIN_W;\n        height = DESKTOP_H;\n        isMaximized = true;\n    }\n}\n\nint PuzzleWindowBase::hitCaptionButton(sf::Vector2f mp) const {\n    if (closeBtnRect().contains(mp)) return 0;\n    if (canMaximize && maxBtnRect().contains(mp)) return 1;\n    if (canMinimize && minBtnRect().contains(mp)) return 2;\n    return -1;\n}\n\nbool PuzzleWindowBase::containsTitleBarDrag(sf::Vector2f mp) const {\n    return titleBarRect().contains(mp) && hitCaptionButton(mp) == -1;\n}\n\nvoid PuzzleWindowBase::renderFrame(sf::RenderWindow& win) {\n    frame.setPosition(position);\n    frame.setSize({width, height});\n    win.draw(frame);\n    drawDoubleBevel(win, bounds(), true);\n\n    titleBar.setPosition(position.x + BORDER, position.y + BORDER);\n    titleBar.setSize({width - 2*BORDER, TITLEBAR_H - BORDER});\n    titleBar.setFillColor(isActive ? C::TitleActive : C::TitleInactive);\n    win.draw(titleBar);\n\n    titleText.setPosition(position.x + BORDER + 4.f, position.y + BORDER + 2.f);\n    win.draw(titleText);\n\n    drawCaptionButton(win, closeBtnRect(), *uiFont, "X", C::CloseBtn);\n    if (canMaximize) drawCaptionButton(win, maxBtnRect(), *uiFont, isMaximized ? "2" : "1", C::BevelMedium);\n    if (canMinimize) drawCaptionButton(win, minBtnRect(), *uiFont, "_", C::BevelMedium);\n}\n\nvoid PuzzleWindowBase::render(sf::RenderWindow& win) {\n    if (!isOpen || isMinimized) return;\n    renderFrame(win);\n    renderContent(win);\n}\n\nbool PuzzleWindowBase::isMouseHit(sf::Vector2f mousePos) {\n    return isOpen && !isMinimized && bounds().contains(mousePos);\n}\n\n// ── NotepadWindow ──────────────────────────────\nNotepadWindow::NotepadWindow(const std::string& fileTitle, const std::string& content, sf::Vector2f p, float w, float h, const sf::Font& font)\n    : PuzzleWindowBase(fileTitle + " - 记事本", p, w, h, font), textContent(content) {\n    docText.setFont(font);\n    docText.setCharacterSize(14);\n    docText.setFillColor(C::TextBlack);\n    \n    // 简单分行处理\n    std::string wrapped;\n    int lineLen = 0;\n    for (char c : content) {\n        if (c == \'\\n\') { lineLen = 0; wrapped += c; }\n        else {\n            wrapped += c;\n            lineLen++;\n            if (lineLen > 50) { wrapped += "\\n"; lineLen = 0; }\n        }\n    }\n    docText.setString(U8(wrapped));\n    canMaximize = true;\n    canMinimize = true;\n}\n\nvoid NotepadWindow::renderContent(sf::RenderWindow& win) {\n    sf::FloatRect cr = clientRect();\n    sf::RectangleShape bg(cr.size);\n    bg.setPosition(cr.position);\n    bg.setFillColor(C::ClientWhite);\n    win.draw(bg);\n    drawDoubleBevel(win, cr, false);\n    \n    docText.setPosition(cr.position.x + 5.f, cr.position.y + 5.f);\n    win.draw(docText);\n}\n\nvoid NotepadWindow::handleInput(const sf::Event& event) {}\n\n// ── BrowserWindow ──────────────────────────────\nBrowserWindow::BrowserWindow(sf::Vector2f p, float w, float h, const sf::Font& font)\n    : PuzzleWindowBase("Windows Internet Explorer", p, w, h, font), winFont(&font) {\n    addressInput = "http://www.spacex.com/history";\n    addrText.setFont(font);\n    addrText.setCharacterSize(14);\n    addrText.setFillColor(C::TextBlack);\n    addrText.setString(U8(addressInput));\n    \n    contentText.setFont(font);\n    contentText.setCharacterSize(14);\n    contentText.setFillColor(C::TextBlack);\n    \n    statusText.setFont(font);\n    statusText.setCharacterSize(12);\n    statusText.setFillColor(C::TextBlack);\n    \n    addrBar.setFillColor(C::ClientWhite);\n    goBtn.setFillColor(C::BevelMedium);\n}\n\nvoid BrowserWindow::renderContent(sf::RenderWindow& win) {\n    sf::FloatRect cr = clientRect();\n    \n    sf::Text lbl(*winFont, U8("地址(D):"), 14u);\n    lbl.setFillColor(C::TextBlack);\n    lbl.setPosition(cr.position.x + 5.f, cr.position.y + 10.f);\n    win.draw(lbl);\n    \n    addrBar.setPosition(cr.position.x + 65.f, cr.position.y + 8.f);\n    addrBar.setSize({cr.width - 130.f, 22.f});\n    win.draw(addrBar);\n    drawDoubleBevel(win, addrBar.getGlobalBounds(), false);\n    \n    addrText.setString(U8(addressInput + (editingAddr && (int)(sf::Clock().getElapsedTime().asSeconds()*2)%2==0 ? "|" : "")));\n    addrText.setPosition(addrBar.getPosition().x + 5.f, addrBar.getPosition().y + 2.f);\n    win.draw(addrText);\n    \n    goBtn.setPosition(cr.position.x + cr.width - 55.f, cr.position.y + 8.f);\n    goBtn.setSize({45.f, 22.f});\n    win.draw(goBtn);\n    drawDoubleBevel(win, goBtn.getGlobalBounds(), true);\n    \n    sf::Text goTxt(*winFont, U8("转到"), 12u);\n    goTxt.setFillColor(C::TextBlack);\n    goTxt.setPosition(goBtn.getPosition().x + 10.f, goBtn.getPosition().y + 3.f);\n    win.draw(goTxt);\n    \n    sf::FloatRect pageRect(cr.position.x, cr.position.y + 40.f, cr.width, cr.height - 60.f);\n    sf::RectangleShape page(pageRect.size);\n    page.setPosition(pageRect.position);\n    page.setFillColor(C::ClientWhite);\n    win.draw(page);\n    drawDoubleBevel(win, pageRect, false);\n    \n    if (showSecretPage) {\n        contentText.setString(U8("【系统覆盖】\\n已接入特斯拉奖励系统。\\n请输入完整密钥：202304202012\\n(请在浏览器弹窗中校验)"));\n    } else {\n        contentText.setString(U8("SpaceX 历史档案库\\n===================\\n重大事件回顾：\\n星舰首飞（Starship Orbital Test Flight）\\n发射日期：20230420\\n...\\n(页面底部小字：密钥后半段与特斯拉Model S出厂编号相关)"));\n    }\n    contentText.setPosition(pageRect.position.x + 10.f, pageRect.position.y + 10.f);\n    win.draw(contentText);\n    \n    sf::RectangleShape sb(sf::Vector2f(cr.width, 20.f));\n    sb.setPosition(cr.position.x, cr.position.y + cr.height - 20.f);\n    sb.setFillColor(C::StatusBar);\n    win.draw(sb);\n    drawDoubleBevel(win, sb.getGlobalBounds(), false);\n    \n    statusText.setString(U8("完成"));\n    statusText.setPosition(sb.getPosition().x + 5.f, sb.getPosition().y + 2.f);\n    win.draw(statusText);\n}\n\nvoid BrowserWindow::handleInput(const sf::Event& event) {\n    if (event.type == sf::Event::MouseButtonPressed && event.mouseButton.button == sf::Mouse::Left) {\n        sf::Vector2f mp(event.mouseButton.x, event.mouseButton.y);\n        if (addrBar.getGlobalBounds().contains(mp)) editingAddr = true;\n        else editingAddr = false;\n        \n        if (goBtn.getGlobalBounds().contains(mp)) navigateToAddress();\n    }\n    if (editingAddr && event.type == sf::Event::TextEntered) {\n        if (event.text.unicode == 8 && !addressInput.empty()) addressInput.pop_back();\n        else if (event.text.unicode >= 32 && event.text.unicode < 128) addressInput += static_cast<char>(event.text.unicode);\n    }\n    if (editingAddr && event.type == sf::Event::KeyPressed && event.key.code == sf::Keyboard::Enter) {\n        navigateToAddress();\n    }\n}\n\nvoid BrowserWindow::navigateToAddress() {\n    if (addressInput == "tesla-prize.local") {\n        showSecretPage = true;\n        if (g_Desktop) g_Desktop->addWindow(new PasswordDialog({position.x+50, position.y+50}, 320, 180, *winFont, 1));\n    } else {\n        showSecretPage = false;\n        StoryManager::getInstance().markBrowserClueSeen();\n    }\n}\n\n// ── FileListWin (通用文件列表，支持文件夹和回收站) ───────\nFileListWin::FileListWin(const std::string& winTitle, bool recycleBin, sf::Vector2f p, float w, float h, const sf::Font& font)\n    : PuzzleWindowBase(winTitle, p, w, h, font), isRecycleBinMode(recycleBin), winFont(&font) {\n    folderPath = recycleBin ? "回收站" : "C:\\\\Documents and Settings\\\\Elon\\\\My Documents";\n    if (recycleBin) {\n        restoreBtn.setFillColor(C::BevelMedium);\n        restoreBtnText.setFont(font);\n        restoreBtnText.setCharacterSize(12);\n        restoreBtnText.setFillColor(C::TextBlack);\n        restoreBtnText.setString(U8("还原选定项目"));\n    }\n}\n\nFileListWin::~FileListWin() {\n    for (auto f : files) delete f;\n    files.clear();\n}\n\nvoid FileListWin::addFile(FileObject* file) { files.push_back(file); }\nfloat FileListWin::listTopY() const { return clientRect().position.y + 45.f; }\n\nvoid FileListWin::renderContent(sf::RenderWindow& win) {\n    sf::FloatRect cr = clientRect();\n    \n    // Address bar area\n    sf::RectangleShape addrBg({cr.width, 35.f});\n    addrBg.setPosition(cr.position.x, cr.position.y);\n    addrBg.setFillColor(C::StatusBar);\n    win.draw(addrBg);\n    \n    sf::Text addrLbl(*winFont, U8("地址(D): " + folderPath), 12u);\n    addrLbl.setFillColor(C::TextBlack);\n    addrLbl.setPosition(cr.position.x + 10.f, cr.position.y + 10.f);\n    win.draw(addrLbl);\n    \n    if (isRecycleBinMode) {\n        restoreBtn.setSize({120.f, 22.f});\n        restoreBtn.setPosition(cr.position.x + cr.width - 130.f, cr.position.y + 6.f);\n        win.draw(restoreBtn);\n        drawDoubleBevel(win, restoreBtn.getGlobalBounds(), true);\n        restoreBtnText.setPosition(restoreBtn.getPosition().x + 15.f, restoreBtn.getPosition().y + 3.f);\n        win.draw(restoreBtnText);\n    }\n    \n    // White background for files\n    sf::FloatRect listRect(cr.position.x, cr.position.y + 35.f, cr.width, cr.height - 35.f);\n    sf::RectangleShape listBg(listRect.size);\n    listBg.setPosition(listRect.position);\n    listBg.setFillColor(C::ClientWhite);\n    win.draw(listBg);\n    drawDoubleBevel(win, listRect, false);\n    \n    // Draw files\n    float sx = listRect.position.x + 20.f;\n    float sy = listRect.position.y + 20.f;\n    for (size_t i = 0; i < files.size(); ++i) {\n        if (i == selectedIdx) {\n            sf::RectangleShape sel({ICON_W + 20.f, ICON_W + 40.f});\n            sel.setPosition(sx - 10.f, sy - 5.f);\n            sel.setFillColor(C::SelectIcon);\n            win.draw(sel);\n        }\n        \n        sf::RectangleShape iconRect({32.f, 32.f});\n        iconRect.setPosition(sx + (ICON_W - 32.f)/2.f, sy);\n        if (files[i]->iconType == "txt") iconRect.setFillColor(sf::Color::White);\n        else if (files[i]->iconType == "locked") iconRect.setFillColor(sf::Color::Yellow);\n        else iconRect.setFillColor(sf::Color::Cyan);\n        win.draw(iconRect);\n        \n        sf::Text fn(*winFont, U8(files[i]->name), 12u);\n        if (i == selectedIdx) {\n            fn.setFillColor(C::TextWhite);\n            sf::FloatRect textBg = fn.getGlobalBounds();\n            sf::RectangleShape tbg({textBg.width + 4.f, textBg.height + 4.f});\n            tbg.setPosition(textBg.left - 2.f, textBg.top - 2.f);\n            tbg.setFillColor(C::SelectBlue);\n            win.draw(tbg);\n        } else {\n            fn.setFillColor(C::TextBlack);\n        }\n        fn.setPosition(sx + ICON_W/2.f - fn.getLocalBounds().width/2.f, sy + 36.f);\n        win.draw(fn);\n        \n        sx += 100.f;\n        if (sx + 100.f > cr.position.x + cr.width) {\n            sx = listRect.position.x + 20.f;\n            sy += 80.f;\n        }\n    }\n}\n\nvoid FileListWin::handleInput(const sf::Event& event) {\n    if (event.type == sf::Event::MouseButtonPressed && event.mouseButton.button == sf::Mouse::Left) {\n        sf::Vector2f mp(event.mouseButton.x, event.mouseButton.y);\n        if (isRecycleBinMode && restoreBtn.getGlobalBounds().contains(mp)) {\n            restoreSelectedFile();\n            return;\n        }\n        \n        float sx = clientRect().position.x + 20.f;\n        float sy = listTopY() + 20.f;\n        selectedIdx = -1;\n        for (size_t i = 0; i < files.size(); ++i) {\n            sf::FloatRect hitBox(sx - 10.f, sy - 5.f, ICON_W + 20.f, ICON_W + 40.f);\n            if (hitBox.contains(mp)) {\n                selectedIdx = (int)i;\n                if (listClickClock.getElapsedTime().asMilliseconds() < DOUBLE_CLICK_MS) {\n                    openSelectedFile();\n                }\n                listClickClock.restart();\n                break;\n            }\n            sx += 100.f;\n            if (sx + 100.f > clientRect().position.x + clientRect().width) {\n                sx = clientRect().position.x + 20.f;\n                sy += 80.f;\n            }\n        }\n    }\n}\n\nvoid FileListWin::openSelectedFile() {\n    if (selectedIdx >= 0 && selectedIdx < files.size()) {\n        files[selectedIdx]->open();\n    }\n}\n\nvoid FileListWin::restoreSelectedFile() {\n    if (selectedIdx >= 0 && selectedIdx < files.size() && files[selectedIdx]->iconType == "txt") {\n        StoryManager::getInstance().onKeyPart2Restored();\n        if (g_Desktop) g_Desktop->addWindow(new MsgBoxWin("回收站", "文件已还原成功！", {position.x+50, position.y+50}, 300, 150, *winFont));\n        refreshFiles(); // Trigger re-render to update icon or list if needed\n    }\n}\n\nvoid FileListWin::refreshFiles() {\n    // optional logic if we dynamically remove file from list\n}\n\nvoid FileListWin::buildClientContextMenu(std::vector<MenuItem>& out, sf::Vector2f mp) {\n    if (selectedIdx >= 0 && selectedIdx < files.size()) {\n        out.push_back({"打开", [this](){ openSelectedFile(); }, true, false, true});\n        if (isRecycleBinMode) {\n            out.push_back({"", nullptr, false, true, false});\n            out.push_back({"还原", [this](){ restoreSelectedFile(); }});\n        }\n    } else {\n        out.push_back({"查看", nullptr, false});\n        out.push_back({"刷新", [this](){ refreshFiles(); }});\n    }\n}\n\n// ── PasswordDialog ──────────────────────────────\nPasswordDialog::PasswordDialog(sf::Vector2f p, float w, float h, const sf::Font& font, int pwdMode)\n    : PuzzleWindowBase(pwdMode == 0 ? "系统安全校验" : "Grok 认证", p, w, h, font), winFont(&font), mode(pwdMode) {\n    isModal = true;\n    canMinimize = false;\n    canMaximize = false;\n    \n    promptText.setFont(font);\n    promptText.setCharacterSize(14);\n    promptText.setFillColor(C::TextBlack);\n    if (mode == 0) promptText.setString(U8("请输入加密档案室访问密钥 (提示:与星舰相关)"));\n    else promptText.setString(U8("请输入完整认证密钥 (数字组合)："));\n    \n    inputText.setFont(font);\n    inputText.setCharacterSize(20);\n    inputText.setFillColor(C::TextBlack);\n    \n    inputField.setFillColor(C::ClientWhite);\n    okBtn.setFillColor(C::BevelMedium);\n    cancelBtn.setFillColor(C::BevelMedium);\n    \n    okText.setFont(font); okText.setCharacterSize(12); okText.setFillColor(C::TextBlack); okText.setString(U8("确定"));\n    cancelText.setFont(font); cancelText.setCharacterSize(12); cancelText.setFillColor(C::TextBlack); cancelText.setString(U8("取消"));\n}\n\nvoid PasswordDialog::renderContent(sf::RenderWindow& win) {\n    sf::FloatRect cr = clientRect();\n    promptText.setPosition(cr.position.x + 20.f, cr.position.y + 20.f);\n    win.draw(promptText);\n    \n    inputField.setPosition(cr.position.x + 20.f, cr.position.y + 50.f);\n    inputField.setSize({cr.width - 40.f, 28.f});\n    win.draw(inputField);\n    drawDoubleBevel(win, inputField.getGlobalBounds(), false);\n    \n    inputText.setString(hasError ? U8("密码错误！") : U8(typedPassword + ((int)(sf::Clock().getElapsedTime().asSeconds()*2)%2==0 ? "|" : "")));\n    if (hasError) inputText.setFillColor(sf::Color::Red);\n    else inputText.setFillColor(C::TextBlack);\n    inputText.setPosition(inputField.getPosition().x + 5.f, inputField.getPosition().y + 2.f);\n    win.draw(inputText);\n    \n    okBtn.setPosition(cr.position.x + cr.width - 180.f, cr.position.y + cr.height - 40.f);\n    okBtn.setSize({70.f, 24.f});\n    win.draw(okBtn);\n    drawDoubleBevel(win, okBtn.getGlobalBounds(), true);\n    okText.setPosition(okBtn.getPosition().x + 22.f, okBtn.getPosition().y + 4.f);\n    win.draw(okText);\n    \n    cancelBtn.setPosition(cr.position.x + cr.width - 90.f, cr.position.y + cr.height - 40.f);\n    cancelBtn.setSize({70.f, 24.f});\n    win.draw(cancelBtn);\n    drawDoubleBevel(win, cancelBtn.getGlobalBounds(), true);\n    cancelText.setPosition(cancelBtn.getPosition().x + 22.f, cancelBtn.getPosition().y + 4.f);\n    win.draw(cancelText);\n}\n\nvoid PasswordDialog::handleInput(const sf::Event& event) {\n    if (event.type == sf::Event::MouseButtonPressed && event.mouseButton.button == sf::Mouse::Left) {\n        sf::Vector2f mp(event.mouseButton.x, event.mouseButton.y);\n        if (hasError) { hasError = false; typedPassword = ""; }\n        if (okBtn.getGlobalBounds().contains(mp)) submitPassword();\n        if (cancelBtn.getGlobalBounds().contains(mp)) closeWindow();\n    }\n    if (event.type == sf::Event::TextEntered) {\n        if (hasError) { hasError = false; typedPassword = ""; }\n        if (event.text.unicode == 8 && !typedPassword.empty()) typedPassword.pop_back();\n        else if (event.text.unicode >= 32 && event.text.unicode < 128 && typedPassword.size() < 20) typedPassword += static_cast<char>(event.text.unicode);\n    }\n    if (event.type == sf::Event::KeyPressed && event.key.code == sf::Keyboard::Enter) {\n        submitPassword();\n    }\n}\n\nvoid PasswordDialog::submitPassword() {\n    if (mode == 0) {\n        if (StoryManager::getInstance().tryUnlockArchive(typedPassword)) {\n            closeWindow();\n            if (g_Desktop) g_Desktop->addWindow(new MsgBoxWin("系统提示", "档案室已解锁。\\n请前往桌面查看机密档案。", {position.x, position.y}, 300, 150, *winFont));\n        } else { hasError = true; }\n    } else {\n        if (StoryManager::getInstance().tryPerfectKey(typedPassword)) {\n            closeWindow();\n        } else { hasError = true; }\n    }\n}\n\n// ── SystemPropWin ──────────────────────────────\nSystemPropWin::SystemPropWin(sf::Vector2f p, float w, float h, const sf::Font& font)\n    : PuzzleWindowBase("系统属性", p, w, h, font), winFont(&font) {\n    canMaximize = false;\n    secretBtn.setFillColor(C::BevelMedium);\n    okBtn.setFillColor(C::BevelMedium);\n    cancelBtn.setFillColor(C::BevelMedium);\n    \n    secretBtnText.setFont(font); secretBtnText.setCharacterSize(12); secretBtnText.setFillColor(C::TextBlack); secretBtnText.setString(U8("加密档案室..."));\n    okText.setFont(font); okText.setCharacterSize(12); okText.setFillColor(C::TextBlack); okText.setString(U8("确定"));\n    cancelText.setFont(font); cancelText.setCharacterSize(12); cancelText.setFillColor(C::TextBlack); cancelText.setString(U8("取消"));\n}\n\nvoid SystemPropWin::renderContent(sf::RenderWindow& win) {\n    sf::FloatRect cr = clientRect();\n    \n    sf::Text info(*winFont, U8("系统:\\nMicrosoft Windows XP\\nProfessional\\n版本 2008\\n\\n注册到:\\nElon Musk\\nSpaceX"), 12u);\n    info.setFillColor(C::TextBlack);\n    info.setPosition(cr.position.x + 20.f, cr.position.y + 20.f);\n    win.draw(info);\n    \n    secretBtn.setPosition(cr.position.x + 20.f, cr.position.y + cr.height - 80.f);\n    secretBtn.setSize({100.f, 24.f});\n    win.draw(secretBtn);\n    drawDoubleBevel(win, secretBtn.getGlobalBounds(), true);\n    secretBtnText.setPosition(secretBtn.getPosition().x + 10.f, secretBtn.getPosition().y + 4.f);\n    win.draw(secretBtnText);\n    \n    okBtn.setPosition(cr.position.x + cr.width - 180.f, cr.position.y + cr.height - 40.f);\n    okBtn.setSize({70.f, 24.f});\n    win.draw(okBtn);\n    drawDoubleBevel(win, okBtn.getGlobalBounds(), true);\n    okText.setPosition(okBtn.getPosition().x + 22.f, okBtn.getPosition().y + 4.f);\n    win.draw(okText);\n    \n    cancelBtn.setPosition(cr.position.x + cr.width - 90.f, cr.position.y + cr.height - 40.f);\n    cancelBtn.setSize({70.f, 24.f});\n    win.draw(cancelBtn);\n    drawDoubleBevel(win, cancelBtn.getGlobalBounds(), true);\n    cancelText.setPosition(cancelBtn.getPosition().x + 22.f, cancelBtn.getPosition().y + 4.f);\n    win.draw(cancelText);\n}\n\nvoid SystemPropWin::handleInput(const sf::Event& event) {\n    if (event.type == sf::Event::MouseButtonPressed && event.mouseButton.button == sf::Mouse::Left) {\n        sf::Vector2f mp(event.mouseButton.x, event.mouseButton.y);\n        if (secretBtn.getGlobalBounds().contains(mp)) {\n            if (g_Desktop) g_Desktop->addWindow(new PasswordDialog({position.x + 50, position.y + 50}, 320, 180, *winFont, 0));\n        }\n        if (okBtn.getGlobalBounds().contains(mp) || cancelBtn.getGlobalBounds().contains(mp)) closeWindow();\n    }\n}\n\n// ── RewardAnimWindow ──────────────────────────────\nRewardAnimWindow::RewardAnimWindow(sf::Vector2f p, float w, float h, const sf::Font& font)\n    : PuzzleWindowBase("系统奖励", p, w, h, font) {\n    congratsText.setFont(font);\n    congratsText.setCharacterSize(18);\n    congratsText.setFillColor(C::TextBlack);\n    congratsText.setStyle(sf::Text::Bold);\n    \n    if (StoryManager::getInstance().hasPerfectClear) {\n        congratsText.setString(U8("★ 完美结局 ★\\n密码校验成功！\\n已解锁：无限制 Grok 永久使用权\\n已解锁：特斯拉 Model S 兑换资格！"));\n    } else {\n        congratsText.setString(U8("☆ 普通结局 ☆\\n基础剧情通关。\\n已解锁：无限制 Grok 永久使用权\\n(提示：似乎还有隐藏页面未探索)"));\n    }\n}\n\nvoid RewardAnimWindow::renderContent(sf::RenderWindow& win) {\n    sf::FloatRect cr = clientRect();\n    sf::RectangleShape bg(cr.size);\n    bg.setPosition(cr.position);\n    bg.setFillColor(C::ClientWhite);\n    win.draw(bg);\n    drawDoubleBevel(win, cr, false);\n    \n    // 闪烁动画\n    if ((int)(animationClock.getElapsedTime().asSeconds() * 2) % 2 == 0) {\n        congratsText.setFillColor(StoryManager::getInstance().hasPerfectClear ? sf::Color(200, 100, 0) : sf::Color::Blue);\n    } else {\n        congratsText.setFillColor(C::TextBlack);\n    }\n    \n    congratsText.setPosition(cr.position.x + 20.f, cr.position.y + 50.f);\n    win.draw(congratsText);\n}\n\nvoid RewardAnimWindow::handleInput(const sf::Event& event) {}\n\n// ── MsgBoxWin ──────────────────────────────\nMsgBoxWin::MsgBoxWin(const std::string& boxTitle, const std::string& message, sf::Vector2f p, float w, float h, const sf::Font& font)\n    : PuzzleWindowBase(boxTitle, p, w, h, font) {\n    isModal = true;\n    canMaximize = false;\n    canMinimize = false;\n    msgText.setFont(font);\n    msgText.setCharacterSize(14);\n    msgText.setFillColor(C::TextBlack);\n    msgText.setString(U8(message));\n    \n    okBtn.setFillColor(C::BevelMedium);\n    okBtnText.setFont(font); okBtnText.setCharacterSize(12); okBtnText.setFillColor(C::TextBlack); okBtnText.setString(U8("确定"));\n}\n\nvoid MsgBoxWin::renderContent(sf::RenderWindow& win) {\n    sf::FloatRect cr = clientRect();\n    msgText.setPosition(cr.position.x + 20.f, cr.position.y + 20.f);\n    win.draw(msgText);\n    \n    okBtn.setPosition(cr.position.x + cr.width/2 - 35.f, cr.position.y + cr.height - 40.f);\n    okBtn.setSize({70.f, 24.f});\n    win.draw(okBtn);\n    drawDoubleBevel(win, okBtn.getGlobalBounds(), true);\n    okBtnText.setPosition(okBtn.getPosition().x + 22.f, okBtn.getPosition().y + 4.f);\n    win.draw(okBtnText);\n}\n\nvoid MsgBoxWin::handleInput(const sf::Event& event) {\n    if (event.type == sf::Event::MouseButtonPressed && event.mouseButton.button == sf::Mouse::Left) {\n        if (okBtn.getGlobalBounds().contains(event.mouseButton.x, event.mouseButton.y)) closeWindow();\n    }\n}\n\n'
